namespace sv_1561faf598a74a45a0efd4307506e506.Services;

public sealed record Recipe(int Id, string Title, string Description, int PrepTimeMinutes);

public interface IRecipeService
{
    Task<List<Recipe>> GetByCuisineAsync(int cuisineId, CancellationToken cancellationToken);
}

public sealed class RecipeService : IRecipeService
{
    private static readonly Dictionary<int, List<Recipe>> RecipesByCuisine = new()
    {
        [1] = new List<Recipe>
        {
            new(1, "Margherita Pizza", "Classic Neapolitan pizza with fresh mozzarella, basil, and San Marzano tomato sauce.", 30),
            new(2, "Risotto alla Milanese", "Creamy saffron-infused Arborio rice cooked slowly in broth with Parmigiano-Reggiano.", 45),
            new(3, "Tiramisu", "Layered dessert of espresso-soaked ladyfingers and mascarpone cream dusted with cocoa.", 40),
            new(4, "Pasta Carbonara", "Spaghetti tossed with guanciale, egg yolks, Pecorino Romano, and black pepper.", 25),
        },
        [2] = new List<Recipe>
        {
            new(5, "Pad Thai", "Stir-fried rice noodles with shrimp, tofu, peanuts, bean sprouts, and tamarind sauce.", 35),
            new(6, "Green Curry", "Aromatic coconut milk curry with Thai basil, bamboo shoots, and green chili paste.", 40),
            new(7, "Tom Yum Soup", "Hot and sour soup with lemongrass, galangal, kaffir lime leaves, and prawns.", 30),
            new(8, "Mango Sticky Rice", "Sweet glutinous rice topped with ripe mango slices and coconut cream.", 50),
        },
        [3] = new List<Recipe>
        {
            new(9, "Tacos al Pastor", "Marinated pork tacos with pineapple, cilantro, and onion on corn tortillas.", 60),
            new(10, "Guacamole", "Fresh avocado dip with lime juice, cilantro, jalapeño, tomato, and onion.", 15),
            new(11, "Chiles en Nogada", "Poblano peppers stuffed with picadillo and topped with walnut cream sauce and pomegranate seeds.", 90),
            new(12, "Churros", "Fried dough pastries coated in cinnamon sugar, served with chocolate dipping sauce.", 45),
        },
    };

    public async Task<List<Recipe>> GetByCuisineAsync(int cuisineId, CancellationToken cancellationToken)
    {
        await Task.Delay(2000, cancellationToken);

        return RecipesByCuisine.TryGetValue(cuisineId, out var recipes)
            ? recipes
            : [];
    }
}

@page "/recipes/{CuisineId:int}"
@rendermode InteractiveServer
@using sv_1561faf598a74a45a0efd4307506e506.Services
@inject IRecipeService RecipeService
@inject ILogger<Recipes> Logger
@implements IAsyncDisposable

<PageTitle>Recipes</PageTitle>

<h1>Recipes — Cuisine @CuisineId</h1>

@if (_error is not null)
{
    <div class="alert alert-danger d-flex justify-content-between align-items-center" role="alert">
        <span>@_error</span>
        <button class="btn btn-outline-danger btn-sm" @onclick="RetryAsync">Retry</button>
    </div>
}
else if (_recipes is null)
{
    <p><em>Loading recipes…</em></p>
}
else
{
    @if (_isRefreshing)
    {
        <div class="alert alert-info py-1 px-2" role="status">Refreshing…</div>
    }

    <div class="mb-3">
        <strong>Sort:</strong>
        <span class="badge @(_sort != "popular" ? "bg-primary" : "bg-secondary") me-1">Newest</span>
        <span class="badge @(_sort == "popular" ? "bg-primary" : "bg-secondary")">Popular</span>
    </div>

    var displayed = SortRecipes(_recipes);

    @if (displayed.Count == 0)
    {
        <p>No recipes found for this cuisine.</p>
    }
    else
    {
        <div class="row">
            @foreach (var recipe in displayed)
            {
                <div class="col-md-6 mb-3">
                    <div class="card">
                        <div class="card-body">
                            <h5 class="card-title">@recipe.Title</h5>
                            <p class="card-text">@recipe.Description</p>
                            <span class="badge bg-secondary">@recipe.PrepTimeMinutes min</span>
                        </div>
                    </div>
                </div>
            }
        </div>
    }
}

@code {
    [Parameter]
    public int CuisineId { get; set; }

    [SupplyParameterFromQuery(Name = "sort")]
    public string? Sort { get; set; }

    private List<Recipe>? _recipes;
    private string? _error;
    private bool _isRefreshing;
    private string? _sort;

    private int _loadedCuisineId;
    private CancellationTokenSource? _cts;
    private bool _disposed;

    public override async Task SetParametersAsync(ParameterView parameters)
    {
        var previousCuisineId = CuisineId;

        await base.SetParametersAsync(parameters);

        // Always keep the local sort value in sync for rendering.
        _sort = Sort;

        // Only reload data when the cuisine actually changes,
        // or on the very first load (previousCuisineId == 0 and _recipes is null).
        if (CuisineId != _loadedCuisineId)
        {
            await LoadRecipesAsync();
        }
    }

    private async Task LoadRecipesAsync()
    {
        // Cancel any in-flight request for the previous cuisine.
        await CancelPendingRequestAsync();

        var isInitialLoad = _recipes is null;
        _error = null;

        if (!isInitialLoad)
        {
            _isRefreshing = true;
        }

        var cts = CancellationTokenSource.CreateLinkedTokenSource(default);
        _cts = cts;

        try
        {
            var result = await RecipeService.GetByCuisineAsync(CuisineId, cts.Token);

            if (!cts.Token.IsCancellationRequested)
            {
                _recipes = result;
                _loadedCuisineId = CuisineId;
            }
        }
        catch (OperationCanceledException)
        {
            // A newer request superseded this one, or the component is disposing. Nothing to do.
        }
        catch (TimeoutException ex)
        {
            Logger.LogError(ex, "Timeout loading recipes for cuisine {CuisineId}", CuisineId);
            _error = "The request timed out. Please try again.";
        }
        catch (Exception ex)
        {
            Logger.LogError(ex, "Error loading recipes for cuisine {CuisineId}", CuisineId);
            _error = "Something went wrong while loading recipes. Please try again.";
        }
        finally
        {
            _isRefreshing = false;
        }
    }

    private List<Recipe> SortRecipes(List<Recipe> recipes)
    {
        return string.Equals(_sort, "popular", StringComparison.OrdinalIgnoreCase)
            ? recipes.OrderBy(r => r.PrepTimeMinutes).ToList()
            : recipes.OrderByDescending(r => r.Id).ToList();
    }

    private async Task RetryAsync()
    {
        await LoadRecipesAsync();
    }

    private async Task CancelPendingRequestAsync()
    {
        if (_cts is not null)
        {
            await _cts.CancelAsync();
            _cts.Dispose();
            _cts = null;
        }
    }

    public async ValueTask DisposeAsync()
    {
        if (_disposed)
        {
            return;
        }
        _disposed = true;
        await CancelPendingRequestAsync();
    }
}

