namespace sv_1561faf598a74a45a0efd4307506e506.Services;

public sealed record Recipe(int Id, string Title, string Description, int PrepTimeMinutes);

public interface IRecipeService
{
    Task<List<Recipe>> GetByCuisineAsync(int cuisineId, CancellationToken cancellationToken);
}

public sealed class RecipeService : IRecipeService
{
    private static readonly Dictionary<int, List<Recipe>> RecipesByCuisine = new()
    {
        [1] = new List<Recipe>
        {
            new(1, "Margherita Pizza", "Classic Neapolitan pizza with fresh mozzarella, basil, and San Marzano tomato sauce.", 30),
            new(2, "Risotto alla Milanese", "Creamy saffron-infused Arborio rice cooked slowly in broth with Parmigiano-Reggiano.", 45),
            new(3, "Tiramisu", "Layered dessert of espresso-soaked ladyfingers and mascarpone cream dusted with cocoa.", 40),
            new(4, "Pasta Carbonara", "Spaghetti tossed with guanciale, egg yolks, Pecorino Romano, and black pepper.", 25),
        },
        [2] = new List<Recipe>
        {
            new(5, "Pad Thai", "Stir-fried rice noodles with shrimp, tofu, peanuts, bean sprouts, and tamarind sauce.", 35),
            new(6, "Green Curry", "Aromatic coconut milk curry with Thai basil, bamboo shoots, and green chili paste.", 40),
            new(7, "Tom Yum Soup", "Hot and sour soup with lemongrass, galangal, kaffir lime leaves, and prawns.", 30),
            new(8, "Mango Sticky Rice", "Sweet glutinous rice topped with ripe mango slices and coconut cream.", 50),
        },
        [3] = new List<Recipe>
        {
            new(9, "Tacos al Pastor", "Marinated pork tacos with pineapple, cilantro, and onion on corn tortillas.", 60),
            new(10, "Guacamole", "Fresh avocado dip with lime juice, cilantro, jalapeño, tomato, and onion.", 15),
            new(11, "Chiles en Nogada", "Poblano peppers stuffed with picadillo and topped with walnut cream sauce and pomegranate seeds.", 90),
            new(12, "Churros", "Fried dough pastries coated in cinnamon sugar, served with chocolate dipping sauce.", 45),
        },
    };

    public async Task<List<Recipe>> GetByCuisineAsync(int cuisineId, CancellationToken cancellationToken)
    {
        await Task.Delay(2000, cancellationToken);

        return RecipesByCuisine.TryGetValue(cuisineId, out var recipes)
            ? recipes
            : [];
    }
}

